const stdout = $input.first().json.stdout || '';
const project = $('Webhook').first().json.query.project;

if (!stdout || stdout.trim() === 'FILE_NOT_FOUND') {
  return [{ json: { hasError: true, errorType: 'file_not_found', project } }];
}

const backlogMatch = stdout.match(/## Backlog[\r\n]([\s\S]*?)(?=[\n]## |[\n]---|$)/m);
const backlogContent = backlogMatch ? backlogMatch[1] : '';

const todos = backlogContent.split('\n')
  .filter(line => line.match(/^- \[ \]\s+/))
  .map(line => line.replace(/^- \[ \]\s+/, '').trim())
  .filter(Boolean);

if (todos.length === 0) {
  return [{ json: { hasError: true, errorType: 'no_todos', project } }];
}

const prompt = `Je bent een senior software engineer die helpt bij projectplanning.\n\nProject: ${project}\n\nBacklog taken:\n${todos.map((t, i) => `${i + 1}. ${t}`).join('\n')}\n\nMaak een concreet implementatieplan in het Nederlands. Geef per taak:\n- Precieze beschrijving van wat gebouwd wordt\n- Concrete stappen (bestanden, functies, endpoints)\n- Geschatte volgorde van implementatie\n\nSchrijf uitsluitend het plan als markdown, zonder inleiding of afsluiting.`;

const base64Prompt = Buffer.from(prompt).toString('base64');
return [{ json: { hasError: false, todos, base64Prompt, project, fileContent: stdout } }];

const fileContent = $('Lees project note').first().json.stdout;
const plan = $input.first().json.stdout.trim();
const project = $('Webhook').first().json.query.project;

let updated = fileContent;
updated = updated.replace(/## Plan[\r\n][\s\S]*?(?=[\n]## |[\n]---|$)/m, '');
updated = updated.replace(/\n{3,}/g, '\n\n');

const planSection = `## Plan\n\n${plan}\n\n`;

if (updated.includes('## Vragen')) {
  updated = updated.replace('## Vragen', planSection + '## Vragen');
} else if (updated.includes('## Taken uitvoeren')) {
  updated = updated.replace('## Taken uitvoeren', planSection + '## Taken uitvoeren');
} else {
  updated = updated.trimEnd() + '\n\n' + planSection;
}

const base64Content = Buffer.from(updated).toString('base64');
return [{ json: { base64Content, project, todoCount: $('Parseer backlog').first().json.todos.length } }];
